     2→import { NAV_ITEMS, SITE_CONFIG } from "../../lib/constants";
     3→import Container from "../ui/Container.astro";
     4→import MobileMenu from "./MobileMenu";
     5→
     6→interface Props {
     7→  transparent?: boolean;
     8→}
     9→
    10→const { transparent = false } = Astro.props;
    11→---
    12→
    13→<header
    14→  id="site-header"
    15→  class:list={[
    16→    "fixed top-0 left-0 right-0 z-50 transition-all duration-300",
    17→    transparent ? "bg-transparent" : "bg-white/95 backdrop-blur-sm shadow-sm",
    18→  ]}
    19→>
    20→  <Container>
    21→    <nav class="flex items-center justify-between h-16 lg:h-20">
    22→      <!-- Logo -->
    23→      <a href="/" class="flex items-center gap-2 text-xl font-bold text-sakura-600 hover:text-sakura-700 transition-colors">
    24→        <span class="sr-only">{SITE_CONFIG.name} ホームに戻る</span>
    25→        <span aria-hidden="true">あいのみ</span>
    26→      </a>
    27→
    28→      <!-- Desktop Navigation -->
    29→      <ul class="hidden md:flex items-center gap-8">
    30→        {NAV_ITEMS.map((item) => (
    31→          <li class="relative group">
    32→            <a
    33→              href={item.href}
    34→              class="text-neutral-700 hover:text-sakura-600 transition-colors py-2 font-medium"
    35→            >
    36→              {item.label}
    37→            </a>
    38→            {item.children && (
    39→              <ul class="absolute top-full left-0 pt-2 opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all duration-200">
    40→                <div class="bg-white rounded-lg shadow-lg border border-neutral-100 py-2 min-w-[180px]">
    41→                  {item.children.map((child) => (
    42→                    <li>
    43→                      <a
    44→                        href={child.href}
    45→                        class="block px-4 py-2 text-neutral-700 hover:text-sakura-600 hover:bg-sakura-50 transition-colors"
    46→                      >
    47→                        {child.label}
    48→                      </a>
    49→                    </li>
    50→                  ))}
    51→                </div>
    52→              </ul>
    53→            )}
    54→          </li>
    55→        ))}
    56→      </ul>
    57→
    58→      <!-- Mobile Menu Button -->
    59→      <div class="md:hidden">
    60→        <MobileMenu client:load navItems={NAV_ITEMS} />
    61→      </div>
    62→    </nav>
    63→  </Container>
    64→</header>
    65→
    66→<!-- Spacer to prevent content from going under fixed header -->
    67→<div class="h-16 lg:h-20" aria-hidden="true"></div>
    68→
    69→<script>
    70→  // Header scroll behavior
    71→  const header = document.getElementById("site-header");
    72→  let lastScrollY = 0;
    73→
    74→  const handleScroll = () => {
    75→    const currentScrollY = window.scrollY;
    76→
    77→    if (header) {
    78→      // Add background when scrolled
    79→      if (currentScrollY > 50) {
    80→        header.classList.remove("bg-transparent");
    81→        header.classList.add("bg-white/95", "backdrop-blur-sm", "shadow-sm");
    82→      } else if (header.dataset.transparent === "true") {
    83→        header.classList.add("bg-transparent");
    84→        header.classList.remove("bg-white/95", "backdrop-blur-sm", "shadow-sm");
    85→      }
    86→    }
    87→
    88→    lastScrollY = currentScrollY;
    89→  };
    90→
    91→  window.addEventListener("scroll", handleScroll, { passive: true });
    92→</script>
